import{_ as t,o as a,c as r,a2 as s}from"./chunks/framework.B6GODI0y.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"implementation/must-have.md","filePath":"implementation/must-have.md","lastUpdated":1783688213000}'),n={name:"implementation/must-have.md"};function i(o,e,d,c,u,h){return a(),r("div",null,[...e[0]||(e[0]=[s('<h2 id="must-have-checking-in-torch-pipeline" tabindex="-1">Must-Have Checking in TORCH Pipeline <a class="header-anchor" href="#must-have-checking-in-torch-pipeline" aria-label="Permalink to &quot;Must-Have Checking in TORCH Pipeline&quot;">​</a></h2><p>The must-have check ensures that extracted data meets the criteria defined in the CRTDL. Required elements are declared in the CRTDL using the <code>mustHave</code> flag on individual attributes.</p><p>Must-have checking is performed after resources are loaded from the FHIR server and again during the reference-resolve step.</p><h2 id="when-musthave-affects-patient-filtering" tabindex="-1">When <code>mustHave</code> affects patient filtering <a class="header-anchor" href="#when-musthave-affects-patient-filtering" aria-label="Permalink to &quot;When `mustHave` affects patient filtering&quot;">​</a></h2><p>An attribute group has an active must-have constraint only when <strong>at least one user-declared attribute</strong> in that group carries <code>mustHave: true</code>.</p><p>When an attribute group has an active must-have constraint:</p><ul><li>A resource satisfies the group&#39;s must-have requirement if its <code>meta.profile</code> matches the group&#39;s <code>groupReference</code> <strong>and</strong> every <code>mustHave: true</code> attribute has a value — i.e., the FHIRPath expression for that attribute returns at least one result (including values present via extensions).</li><li>A patient is <strong>retained</strong> in the result if at least one resource of that group satisfies the requirement.</li><li>A patient is <strong>dropped</strong> from the result if none of their resources satisfy the requirement for that group.</li></ul><p>When a group has no user-declared <code>mustHave: true</code> attribute, the group is optional: all patients are retained regardless of whether they have any resources for that group.</p><h3 id="standard-attributes-and-musthave" tabindex="-1">Standard attributes and <code>mustHave</code> <a class="header-anchor" href="#standard-attributes-and-musthave" aria-label="Permalink to &quot;Standard attributes and `mustHave`&quot;">​</a></h3><p>Standard attributes (<code>id</code>, <code>meta.profile</code>, and patient compartment references such as <code>subject</code>) are always injected by TORCH for functional reasons — they are required for internal processing, referential integrity, and profile-aware handling.</p><p>Standard attributes are <strong>technically enforced at pipeline level</strong>: resources that lack <code>id</code> or <code>meta.profile</code> are filtered out before must-have checking runs. Because of this, standard attributes are always generated with <code>mustHave: false</code> and never count towards the group&#39;s must-have constraint. They are never the reason a patient is dropped.</p><p>The <code>mustHave</code> flag is purely user-driven: it expresses a <strong>data quality requirement</strong> — that a certain clinical field must have a value for the resource to be meaningful to the requester.</p><p>Declaring a standard attribute with <code>mustHave: true</code> in the CRTDL is a validation error, because standard attributes are not user-controlled data quality requirements and cannot be used to drive patient filtering. Declaring a standard attribute with <code>mustHave: false</code> is redundant and silently skipped.</p><h2 id="_1-field-must-have-check" tabindex="-1">1. Field Must-Have Check <a class="header-anchor" href="#_1-field-must-have-check" aria-label="Permalink to &quot;1. Field Must-Have Check&quot;">​</a></h2><p>Based on FHIRPath expressions, the must-have check verifies that all <code>mustHave: true</code> attributes have a value in a resource. If a resource fails the check, it is still loaded but not counted towards satisfying the group&#39;s must-have requirement.</p><h2 id="_2-reference-resolve" tabindex="-1">2. Reference Resolve <a class="header-anchor" href="#_2-reference-resolve" aria-label="Permalink to &quot;2. Reference Resolve&quot;">​</a></h2><p>A reference attribute in the CRTDL can be marked as <code>mustHave: true</code> and linked to other attribute groups that define requirements for the referenced resource.</p><p>During <a href="./reference-resolve.html">Reference Resolve</a>, TORCH checks both that the reference can be resolved and that the resolved resource passes the must-have check for the linked attribute groups.</p><p>If any must-have condition is violated, the referencing resource is marked for deletion and removed during the <a href="./cascading-delete.html">cascading delete</a> step.</p>',19)])])}const f=t(n,[["render",i]]);export{p as __pageData,f as default};
